#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;


//Shader from Marten Range
//https://www.shadertoy.com/view/tfK3Dy
//Ported to MilkDrop by MilkDrop2077

    vec4 o = vec4(0,0,0,0);
    vec4 P, p;
    vec4 U = vec4(1,2,3,0);

    // Musical timing using audioLowSmooth for volume sensitivity
    float T = uTime * 2.0 * 0.5;
    float F = fract(T);
    float t = floor(T) + sqrt(F);

    // Create rotation matrices
    float angle = t*0.1 + 11.0*U.w;
    mat2 R = transpose(mat2(cos(angle), -sin(angle), sin(angle), cos(angle)));
    // In GLSL is column-major order and in HLSL, row-major order,
    // So we transpose the matrix with transpose() to be the same as GLSL.

    // Raymarching loop
    float z = 0.0;
    for(float i=0.0; i<77.0; i+=1.0) {
        // Create ray from camera
        vec2 centered_uv = (vUv - 0.5) * uAspect.xy;
        centered_uv.y = -centered_uv.y; //Flip UV
        p = vec4(z*normalize(vec3(centered_uv, 1.0)), 0.2);

        // Move camera back
        p.z -= 3.0;

        // Apply rotations to different planes
        p.xw = vec2(p.x*R[0][0] + p.w*R[0][1], p.x*R[1][0] + p.w*R[1][1]);
        p.yw = vec2(p.y*R[0][0] + p.w*R[0][1], p.y*R[1][0] + p.w*R[1][1]);
        p.zw = vec2(p.z*R[0][0] + p.w*R[0][1], p.z*R[1][0] + p.w*R[1][1]);

        // Inversion
        float k = 9.0/dot(p,p);
        p *= k;

        // Offset by uTime
        P = p -= 0.5*t+q7;

        // Fold space
        p = abs(p - round(p));

        // Distance field calculation
        float d = abs(min(
            min(min(length(p.xz), length(p.yz)), length(p.xy)),
            min(length(p)-0.2, min(p.w, min(p.x, min(p.z, p.y))) + 0.05
        ))/k);

        z += 0.8*d + 1e-3;

        // Color calculation
        p = 1.0 + sin(P.z + log2(k) + U.wxyw);

        // Accumulate color with beat fade
        o += U*exp(0.5*k - 6.0*F) + p.w*p/max(d, 1e-3);
    }

    float brightness = 0.5 + 0.5;
    o = clamp(o/1e4 * brightness, -6.0, 6.0);   // <- keeps tanh happy
    ret = tanh(o)/0.9;

  fragColor = ret;
}

